                file_path = os.path.join(media_dir, os.path.basename(url))
                if os.path.exists(file_path):
                    try:
                        audio = AudioSegment.from_file(file_path)
                    except Exception as e:
                        print(f"Warning: Could not load audio file {file_path}: {e}")
                        continue
                else:
